import{_ as e,o as t,c as l,a0 as o}from"./chunks/framework.AQcSKqPn.js";const u=JSON.parse('{"title":"等价交换","description":"","frontmatter":{"type":"concept","title":"等价交换","tags":["alchemy","philosophy","fullmetal-alchemist"],"related":["fullmetal-alchemist-brotherhood","human-transmutation"],"sources":["anime/5114.md"],"created":"2026-07-10T00:00:00.000Z","updated":"2026-07-10T00:00:00.000Z","date":"2026-07-10T00:00:00.000Z"},"headers":[],"relativePath":"concepts/等价交换.md","filePath":"concepts/等价交换.md","lastUpdated":1783993461000}'),r={name:"concepts/等价交换.md"};function i(n,a,s,c,h,d){return t(),l("div",null,[...a[0]||(a[0]=[o('<h1 id="等价交换" tabindex="-1">等价交换 <a class="header-anchor" href="#等价交换" aria-label="Permalink to &quot;等价交换&quot;">​</a></h1><p>等价交换（Equivalent Exchange）是炼金术的基本原则，其核心思想是&quot;获得某物，必须付出同等的代价&quot;。在《钢之炼金术师 FULLMETAL ALCHEMIST》中，这一原则既是炼金术的操作法则，也是贯穿全剧的哲学框架。</p><h2 id="在《钢之炼金术师》中的角色" tabindex="-1">在《钢之炼金术师》中的角色 <a class="header-anchor" href="#在《钢之炼金术师》中的角色" aria-label="Permalink to &quot;在《钢之炼金术师》中的角色&quot;">​</a></h2><p>等价交换原则在作品中以多种形式呈现。艾尔利克兄弟试图通过人体炼成复活母亲，却付出了身体残缺的代价——这既是对等价交换的体现，也暗示了其局限性。作品通过这一原则探讨了牺牲、代价、生命价值等深刻主题。</p><h2 id="与人体炼成的关系" tabindex="-1">与人体炼成的关系 <a class="header-anchor" href="#与人体炼成的关系" aria-label="Permalink to &quot;与人体炼成的关系&quot;">​</a></h2><p><a href="/llm-wiki/concepts/人体炼成">human-transmutation</a>作为禁忌行为，直接挑战了等价交换原则的边界。人体炼成的失败表明，某些事物（如生命）的价值可能超出了物质交换的范畴。</p><h2 id="相关页面" tabindex="-1">相关页面 <a class="header-anchor" href="#相关页面" aria-label="Permalink to &quot;相关页面&quot;">​</a></h2><ul><li><a href="/llm-wiki/entities/钢之炼金术师-fullmetal-alchemist">fullmetal-alchemist-brotherhood</a> — 作品实体页面</li><li><a href="/llm-wiki/concepts/人体炼成">human-transmutation</a> — 人体炼成</li></ul>',8)])])}const p=e(r,[["render",i]]);export{u as __pageData,p as default};
